// ── DB persistence helpers ────────────────────────────────────
function debounce(fn, ms) {
  let t; return (...a) => { clearTimeout(t); t = setTimeout(() => fn(...a), ms); };
}
const _saveState = async (userId, patch) => {
  if (!userId) return;
  let cleanPatch = patch;
  // Strip base64/blob URLs from gallery_photos (too large for DB row)
  if (patch.gallery_photos) {
    const cleanPhotos = {};
    for (const [projId, arr] of Object.entries(patch.gallery_photos)) {
      cleanPhotos[projId] = (arr || []).filter(ph => ph.url && !ph.url.startsWith("data:") && !ph.url.startsWith("blob:") && !ph.uploading);
    }
    cleanPatch = { ...cleanPatch, gallery_photos: cleanPhotos };
  }
  // Strip blob URLs from video_deliverables (blob: URLs are session-only, not cross-session)
  if (patch.video_deliverables) {
    const cleanVids = {};
    for (const [projId, dels] of Object.entries(patch.video_deliverables)) {
      cleanVids[projId] = (dels || []).map(del => ({
        ...del,
        versions: (del.versions || []).map(v => ({
          ...v,
          url: (v.url && !v.url.startsWith("blob:")) ? v.url : null,
        })),
      }));
    }
    cleanPatch = { ...cleanPatch, video_deliverables: cleanVids };
  }
  await supabase.from("app_state").upsert(
    { user_id: userId, ...cleanPatch, updated_at: new Date().toISOString() },
    { onConflict: "user_id" }
  );
};
const saveState = debounce(_saveState, 1500);

// ── Login / Signup Screen ─────────────────────────────────────
function AuthScreen({ onAuth }) {
  const [mode, setMode]       = useState("login");
  const [email, setEmail]     = useState("");
  const [password, setPassword] = useState("");
  const [name, setName]       = useState("");
  const [studio, setStudio]   = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState("");

  const inp = {
    width:"100%", padding:"12px 16px",
    background:"rgba(255,255,255,0.08)", border:"1px solid rgba(255,255,255,0.15)",
    borderRadius:8, color:"#fff", fontSize:14, outline:"none",
    marginBottom:12, boxSizing:"border-box",
  };
  const btn = {
    width:"100%", padding:"14px",
    background:"linear-gradient(135deg,#2d5a45,#3d7a5e)",
    color:"#fff", border:"none", borderRadius:8,
    fontSize:15, fontWeight:600, cursor:"pointer", marginTop:4,
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true); setError("");
    try {
      if (mode === "signup") {
        // Sign up — the database trigger auto-creates org, profile & brand kit
        const { data, error: signUpError } = await supabase.auth.signUp({
          email, password,
          options: { data: { full_name: name, org_name: studio } },
        });
        if (signUpError) throw signUpError;
        if (data.session) {
          onAuth(data.session);
        } else {
          // Email confirmation enabled — sign in immediately after
          const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({ email, password });
          if (signInError) throw new Error("Account created! Please sign in.");
          onAuth(signInData.session);
        }
      } else {
        const { data, error: signInError } = await supabase.auth.signInWithPassword({ email, password });
        if (signInError) throw signInError;
        onAuth(data.session);
      }
    } catch(err) {
      setError(err.message || "Something went wrong");
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight:"100vh", background:"linear-gradient(160deg,#0b1410 0%,#111e18 50%,#0e1a15 100%)",
      display:"flex", alignItems:"center", justifyContent:"center",
      fontFamily:"'Inter',sans-serif",
    }}>
      <div style={{ width:"100%", maxWidth:400, padding:"0 24px" }}>
        <div style={{ textAlign:"center", marginBottom:36 }}>
          <div style={{
            width:56,height:56,background:"#0d0d0d",
            borderRadius:14,margin:"0 auto 16px",display:"flex",
            alignItems:"center",justifyContent:"center",
            boxShadow:"0 0 0 1px rgba(255,255,255,0.08)",
          }}>
            {/* Minimalist aperture / lens mark */}
            <svg width="28" height="28" viewBox="0 0 28 28" fill="none" xmlns="http://www.w3.org/2000/svg">
              <circle cx="14" cy="14" r="11" stroke="rgba(255,255,255,0.85)" strokeWidth="1.5"/>
              <circle cx="14" cy="14" r="4.5" fill="rgba(255,255,255,0.9)"/>
              <line x1="14" y1="3" x2="14" y2="8.5" stroke="rgba(255,255,255,0.5)" strokeWidth="1.5" strokeLinecap="round"/>
              <line x1="14" y1="19.5" x2="14" y2="25" stroke="rgba(255,255,255,0.5)" strokeWidth="1.5" strokeLinecap="round"/>
              <line x1="3" y1="14" x2="8.5" y2="14" stroke="rgba(255,255,255,0.5)" strokeWidth="1.5" strokeLinecap="round"/>
              <line x1="19.5" y1="14" x2="25" y2="14" stroke="rgba(255,255,255,0.5)" strokeWidth="1.5" strokeLinecap="round"/>
            </svg>
          </div>
          <h1 style={{ color:"#fff",margin:0,fontSize:28,fontWeight:700,letterSpacing:"-.5px" }}>FrameFlow</h1>
          <p style={{ color:"rgba(255,255,255,0.4)",margin:"8px 0 0",fontSize:14 }}>
            {mode==="login" ? "Sign in to your studio" : "Create your studio account"}
          </p>
        </div>
        <form onSubmit={handleSubmit}>
          {mode==="signup" && <>
            <input style={inp} placeholder="Your full name" value={name} onChange={e=>setName(e.target.value)} required />
            <input style={inp} placeholder="Studio / business name" value={studio} onChange={e=>setStudio(e.target.value)} required />
          </>}
          <input style={inp} type="email" placeholder="Email address" value={email} onChange={e=>setEmail(e.target.value)} required />
          <input style={inp} type="password" placeholder="Password (min 8 chars)" value={password} onChange={e=>setPassword(e.target.value)} required minLength={8} />
          {error && <div style={{ background:"rgba(239,68,68,0.15)",border:"1px solid rgba(239,68,68,0.3)",color:"#fca5a5",padding:"10px 14px",borderRadius:8,fontSize:13,marginBottom:12 }}>{error}</div>}
          <button type="submit" style={{...btn, opacity:loading?0.7:1}} disabled={loading}>
            {loading ? "…" : mode==="login" ? "Sign In →" : "Create Account →"}
          </button>
          <p style={{ textAlign:"center",color:"rgba(255,255,255,0.35)",fontSize:13,marginTop:16 }}>
            {mode==="login" ? "No account? " : "Already have one? "}
            <span onClick={()=>{setMode(mode==="login"?"signup":"login");setError("");}}
              style={{ color:"#6bbf95",cursor:"pointer",textDecoration:"underline" }}>
              {mode==="login" ? "Sign up free" : "Sign in"}
            </span>
          </p>
        </form>
      </div>
    </div>
  );
}

