const genContract = (type, f) => {
  const photographer = (brandKit?.studioName || "Your Studio") + " LLC";
  const photographerAddress = "1204 NW Glisan St, Portland, OR 97209";
  const typeLabel = { wedding:"Wedding Photography", portrait:"Portrait Photography", commercial:"Commercial Photography", video:"Video Production" }[type];

  const sections = [
`1. PARTIES
This ${typeLabel} Services Agreement ("Agreement") is entered into as of ${f.date || "[Date]"} between ${photographer} ("Photographer/Videographer"), located at ${photographerAddress}, and ${f.clientName || "[Client Name]"} ("Client"), located at ${f.clientAddress || "[Client Address]"} (collectively, the "Parties").`,

`2. SERVICES
Photographer agrees to provide ${typeLabel} services for ${type==="wedding" ? `the wedding event of ${f.clientName || "[Client]"} scheduled on ${f.eventDate || "[Event Date]"} at ${f.location || "[Venue]"}` : type==="portrait" ? `a portrait session scheduled on ${f.eventDate || "[Session Date]"} at ${f.location || "[Location]"}` : type==="commercial" ? `commercial photography services for ${f.projectName || "[Project Name]"} as described in the attached scope` : `video production services for "${f.projectName || "[Project]"}" as outlined in the attached creative brief`}. ${type==="wedding" ? `Coverage shall be approximately ${f.hours || "8"} hours.` : ""} Services include: ${f.deliverables || "[Deliverables to be specified]"}.`,

`3. PAYMENT TERMS
The total fee for services is $${f.totalFee || "0.00"}. A non-refundable retainer of $${f.retainer || "0.00"} is due upon signing this Agreement to reserve the date. The remaining balance of $${f.balance || "0.00"} is due on or before ${f.balanceDue || "[Balance Due Date]"}. All payments are due in full prior to delivery of final images/footage. Late payments will accrue interest at 1.5% per month. Returned checks incur a $35 fee.`,

`4. CANCELLATION & RESCHEDULING
(a) By Client: The retainer is non-refundable under all circumstances. If Client cancels within ${f.cancelDays || "90"} days of the event, 100% of the total fee is owed. Cancellation between ${f.cancelDays || "90"} and 180 days prior to the event results in forfeiture of 50% of the total fee. (b) By Photographer: In the unlikely event Photographer must cancel due to emergency or illness, Photographer will make every effort to arrange a qualified substitute photographer. If no substitute can be found, all payments beyond the retainer shall be refunded. (c) Rescheduling: One rescheduling is permitted at no charge with ${f.rescheduleNotice || "30"} days' notice, subject to Photographer's availability.`,

`5. COPYRIGHT & INTELLECTUAL PROPERTY
All photographs and video content created under this Agreement are protected by copyright law (17 U.S.C.). Photographer retains full copyright ownership of all images and footage produced. ${type==="commercial" ? `Upon receipt of final payment, Client receives an exclusive, perpetual, worldwide license to use the delivered content for the commercial purposes specified in this Agreement. Any use beyond the agreed scope requires a separate licensing agreement.` : `Client receives a non-exclusive, non-transferable personal use license to reproduce, display, and share the delivered images/footage for personal, non-commercial purposes only. Images may not be sold, licensed to third parties, altered without consent, or submitted for commercial use without prior written approval from Photographer.`}`,

`6. IMAGE DELIVERY & ARCHIVING
Photographer will deliver ${type==="video" ? "final edited footage" : "final edited images"} within ${f.turnaround || "6–8 weeks"} of the ${type==="wedding" ? "event" : "session"} date via ${f.deliveryMethod || "an online digital gallery"}. ${type!=="video" ? `Client will receive approximately ${f.imageCount || "[number]"} ${type==="commercial" ? "high-resolution retouched images" : "fully edited digital images"}.` : `Deliverables include: ${f.videoDeliverables || "[video deliverables]"}.`} ${type==="video" ? `Client is entitled to ${f.revisions || "2"} rounds of revisions. Additional revision rounds will be billed at $150/hour.` : ""} RAW/unedited files are not included and will not be provided. Photographer will archive images for ${f.archivePeriod || "12 months"} after delivery; Client is responsible for backup thereafter.`,

`7. PHOTOGRAPHER'S USAGE RIGHTS
Client grants Photographer a royalty-free, worldwide license to display, reproduce, and publish the images/footage for Photographer's portfolio, website, social media, and professional marketing materials${type==="commercial" ? ", unless Client requests confidentiality in writing prior to shoot" : ""}. Photographer will credit Client appropriately where practical.`,

`8. MODEL RELEASE
Client, and any subjects who are minors for whom Client is the legal guardian, consent to Photographer's use of images/footage as described in Section 7. Client warrants they have obtained valid releases from all identifiable individuals appearing in the content, or that such releases are not required by law.`,

`9. CLIENT RESPONSIBILITIES
Client is responsible for: (a) providing accurate event information; (b) ensuring Photographer has reasonable access to subjects and locations; (c) informing Photographer of any venue restrictions on photography or lighting; (d) ensuring cooperative subjects are available during the session. Photographer is not responsible for missed moments due to uncooperative subjects, late arrivals, or venue restrictions not disclosed in advance.`,

`10. LIMITATION OF LIABILITY
In the event of equipment failure, accident, illness, or circumstances beyond Photographer's reasonable control, Photographer's total liability is limited to the amount paid under this Agreement. Photographer is not liable for any indirect, consequential, or incidental damages. In the event of total loss of images/footage due to equipment failure or unforeseeable circumstances, Client's sole remedy is a full refund of all amounts paid.`,

`11. FORCE MAJEURE
Neither Party shall be liable for any failure or delay caused by circumstances beyond their reasonable control, including but not limited to acts of God, natural disasters, government orders, pandemic, or civil unrest. In such event, Parties shall negotiate in good faith to reschedule services.`,

`12. INDEPENDENT CONTRACTOR
Photographer is an independent contractor and not an employee of Client. Photographer retains the right to photograph/film additional events on the same date, provided it does not conflict with the Services outlined herein.`,

`13. ENTIRE AGREEMENT & AMENDMENTS
This Agreement constitutes the entire agreement between the Parties regarding the subject matter hereof and supersedes all prior negotiations, representations, and understandings. Any amendments must be made in writing and signed by both Parties.`,

`14. GOVERNING LAW & DISPUTE RESOLUTION
This Agreement shall be governed by the laws of the State of ${f.state || "Oregon"}. Any disputes shall first be attempted to be resolved through good-faith mediation. If mediation fails, disputes shall be resolved by binding arbitration in ${f.city || "Portland, OR"} under the rules of the American Arbitration Association. The prevailing Party is entitled to recover reasonable attorneys' fees.`,
  ];

  return sections;
};

