const COMMUNITY_MEMBERS = [];
const COMMUNITY_GROUPS = [];
const COMMUNITY_POSTS = [];

// ── Video Review Seed Data ────────────────────────────────────
const VIDEO_PROJECTS = [];

let _commentId = 100;
const mkId = () => ++_commentId;

const INITIAL_COMMENTS = {};

// ── Shared Components ─────────────────────────────────────────
const Badge = ({ s }) => {
  const m = {
    "In Progress": { bg:"#eeeded", color:"#7a8c9e", border:"#d0ccc7" },
    "Delivered":   { bg:"#edf0ec", color:"#5c7a68", border:"#c3ccc0" },
    "Editing":     { bg:"#f5f0fb", color:"#6d41b0", border:"#d5c2f0" },
    "Shooting":    { bg:"#f4ede3", color:"#9e7850", border:"#d9c9b0" },
    "Paid":        { bg:"#edf0ec", color:"#5c7a68", border:"#c3ccc0" },
    "Pending":     { bg:"#f4ede3", color:"#9e7850", border:"#d9c9b0" },
    "Overdue":     { bg:"#f2eeeb", color:"#9e5a4a", border:"#d4bab0" },
  };
  const t = m[s] || { bg:"#f3f3f3", color:"#666", border:"#ddd" };
  return (
    <span style={{ background: t.bg, color: t.color, border:`1px solid ${t.border}`, fontSize:11, fontWeight:500, padding:"3px 10px", borderRadius:99, letterSpacing:.2, whiteSpace:"nowrap" }}>
      {s}
    </span>
  );
};

const Btn = ({ children, variant="primary", onClick, icon, style={}, disabled=false }) => {
  const base = { display:"inline-flex", alignItems:"center", gap:6, fontFamily:"Inter,sans-serif", fontWeight:500, fontSize:13, borderRadius:10, cursor:"pointer", border:"none", transition:"all .15s", padding:"9px 16px", ...style };
  const v = {
    primary:   { background:C.ink, color:"#fff" },
    secondary: { background:C.warm, color:C.ink, border:`1px solid ${C.border}` },
    ghost:     { background:"transparent", color:C.muted, padding:"8px 12px" },
    accent:    { background:C.accent, color:"#fff" },
    danger:    { background:"#f2eeeb", color:C.red, border:`1px solid #f2c0b5` },
  };
  return <button style={{...base, ...v[variant]}} onClick={onClick} disabled={disabled}>{icon && <Ic d={P[icon]} size={14}/>}{children}</button>;
};

const Card = ({ children, style={}, onClick }) => (
  <div onClick={onClick} style={{ background:"#faf7f3", borderRadius:16, border:"1px solid #ddd8d2", overflow:"hidden", ...style }}>
    {children}
  </div>
);

const Stat = ({ label, value, sub, icon, color="default", onClick }) => {
  const [hov, setHov] = useState(false);
  const colors = { default:"#f7f5f2", blue:"#eeeded", green:"#edf0ec", amber:"#f4ede3", red:"#f2eeeb" };
  const iconColors = { default:C.muted, blue:"#7a8c9e", green:"#5c7a68", amber:"#9e7850", red:C.red };
  return (
    <Card
      onClick={onClick}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        padding:20, cursor: onClick ? "pointer" : "default",
        transform: hov && onClick ? "translateY(-2px)" : "none",
        boxShadow: hov && onClick ? "0 6px 20px rgba(0,0,0,.10)" : undefined,
        transition:"transform .15s ease, box-shadow .15s ease",
      }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
        <div>
          <p style={{ fontSize:12, color:C.muted, marginBottom:6, letterSpacing:.3, textTransform:"uppercase" }}>{label}</p>
          <p style={{ fontSize:26, fontWeight:600, color:C.ink, lineHeight:1, fontFamily:"'Cormorant Garamond',serif", letterSpacing:-.5 }}>{value}</p>
          {sub && <p style={{ fontSize:12, color:C.muted, marginTop:5 }}>{sub}</p>}
        </div>
        <div style={{ width:38, height:38, borderRadius:10, background:colors[color], display:"flex", alignItems:"center", justifyContent:"center" }}>
          <Ic d={P[icon]} size={17} style={{ color:iconColors[color] }}/>
        </div>
      </div>
      {onClick && <p style={{ fontSize:11, color:C.muted, marginTop:10, opacity: hov ? 1 : 0, transition:"opacity .15s" }}>View →</p>}
    </Card>
  );
};

const ProgressBar = ({ value, max, color=C.ink }) => {
  const pct = Math.round((value / max) * 100);
  return (
    <div>
      <div style={{ display:"flex", justifyContent:"space-between", fontSize:12, color:C.muted, marginBottom:6 }}>
        <span>Payment progress</span>
        <span style={{ color:C.ink, fontWeight:500 }}>${value.toLocaleString()} / ${max.toLocaleString()}</span>
      </div>
      <div style={{ height:4, background:"#ede9e4", borderRadius:99, overflow:"hidden" }}>
        <div style={{ height:"100%", width:`${pct}%`, background:color, borderRadius:99, transition:"width .4s ease" }}/>
      </div>
      <p style={{ fontSize:11, color:C.muted, marginTop:4 }}>{pct}% paid</p>
    </div>
  );
};

// ── Alert List (Needs Attention) ──────────────────────────────
const ALERTS = [];
const AlertList = ({ setPage }) => {
  const [hov, setHov] = useState(null);
  const bg = { red:"#f2eeeb", amber:"#f4ede3", blue:"#eeeded", green:"#edf0ec" };
  const bc = { red:"#d4bab0", amber:"#d9c9b0", blue:"#d0ccc7", green:"#c3ccc0" };
  const tc = { red:C.red, amber:"#9e7850", blue:"#7a8c9e", green:"#5c7a68" };
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
      {ALERTS.map((a,i) => (
        <div
          key={i}
          onClick={() => setPage(a.page)}
          onMouseEnter={() => setHov(i)}
          onMouseLeave={() => setHov(null)}
          style={{
            display:"flex", alignItems:"center", gap:12,
            padding:"11px 13px",
            background: hov===i ? bc[a.type] : bg[a.type],
            borderRadius:12,
            border:`1px solid ${bc[a.type]}`,
            cursor:"pointer",
            transition:"background .15s ease, transform .15s ease",
            transform: hov===i ? "translateX(3px)" : "none",
          }}>
          <Ic d={P[a.icon]} size={16} style={{ color:tc[a.type], flexShrink:0 }}/>
          <div style={{ flex:1 }}>
            <p style={{ fontSize:13, fontWeight:500, color:tc[a.type] }}>{a.title}</p>
            <p style={{ fontSize:11, color:tc[a.type], opacity:.8, marginTop:2 }}>{a.sub}</p>
          </div>
          <Ic d={P.arrow} size={14} style={{ color:tc[a.type], opacity: hov===i ? 1 : 0, transition:"opacity .15s", flexShrink:0 }}/>
        </div>
      ))}
    </div>
  );
};

// ── Dashboard ─────────────────────────────────────────────────
const Dashboard = ({ setPage, goProject, brandKit, supabaseSession, appProjects, appInvoices, appThreads }) => {
  const projects  = appProjects  || [];
  const invoices  = appInvoices  || [];
  const threads   = appThreads   || [];

  // Compute stats from live data
  const activeProjects  = projects.filter(p => p.status !== "Delivered");
  const pendingInvoices = invoices.filter(i => i.status === "Pending" || i.status === "Overdue");
  const outstanding     = pendingInvoices.reduce((s, i) => s + (i.total || i.amount || (i.items||[]).reduce((a,x)=>a+(x.qty||1)*(x.rate||0),0) || 0), 0);
  const unreadMessages  = threads.reduce((s, t) => s + (t.unread || 0), 0);
  const now             = new Date();
  const curMonth        = now.toLocaleString("default", { month: "short" });
  const monthRevenue    = invoices
    .filter(i => i.status === "Paid" && i.date && new Date(i.date).getMonth() === now.getMonth())
    .reduce((s, i) => s + (i.total || i.amount || (i.items||[]).reduce((a,x)=>a+(x.qty||1)*(x.rate||0),0) || 0), 0);

  const firstName = (brandKit?.studioName || supabaseSession?.user?.user_metadata?.full_name || "").split(" ")[0] || "there";
  const hour      = now.getHours();
  const greeting  = hour < 12 ? "Good morning" : hour < 17 ? "Good afternoon" : "Good evening";

  return (
  <div className="fade-in" style={{ display:"flex", flexDirection:"column", gap:24 }}>
    <div>
      <h1 className="serif" style={{ fontSize:32, fontWeight:500, color:C.ink, marginBottom:4 }}>{greeting}{firstName ? `, ${firstName}` : ""}.</h1>
      <p style={{ fontSize:14, color:C.muted }}>Here's your business overview for today.</p>
    </div>

    <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:14 }}>
      <Stat label="Active Projects" value={String(activeProjects.length)}
        sub={activeProjects.length === 0 ? "No active projects" : `${activeProjects.length} in progress`}
        icon="folder" color="blue" onClick={() => setPage("projects")}/>
      <Stat label="Outstanding" value={outstanding > 0 ? `$${outstanding.toLocaleString()}` : "$0"}
        sub={pendingInvoices.length === 0 ? "All invoices paid" : `${pendingInvoices.length} invoice${pendingInvoices.length>1?"s":""} pending`}
        icon="dollar" color="amber" onClick={() => setPage("finance")}/>
      <Stat label="Messages" value={String(unreadMessages)}
        sub={unreadMessages === 0 ? "No unread messages" : `Unread from clients`}
        icon="users" color="default" onClick={() => setPage("inbox")}/>
      <Stat label={`Revenue (${curMonth})`} value={monthRevenue > 0 ? `$${monthRevenue.toLocaleString()}` : "$0"}
        sub={monthRevenue === 0 ? "No revenue recorded yet" : "This month"}
        icon="check" color="green" onClick={() => setPage("finance")}/>
    </div>

    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 340px", gap:14 }}>

      {/* Active Projects */}
      <Card style={{ padding:22, gridColumn:"1/3" }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:18 }}>
          <h2 style={{ fontSize:15, fontWeight:600, color:C.ink }}>Active Projects</h2>
          <button onClick={() => setPage("projects")} style={{ fontSize:12, color:C.muted, background:"none", border:"none", cursor:"pointer" }}>View all →</button>
        </div>
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          {activeProjects.length === 0 ? (
            <div style={{ padding:"32px 0", textAlign:"center" }}>
              <p style={{ fontSize:13, color:C.muted, marginBottom:10 }}>No active projects yet.</p>
              <button onClick={() => setPage("projects")} style={{ padding:"8px 18px", background:C.ink, color:"#fff", border:"none", borderRadius:9, fontSize:12, fontWeight:600, cursor:"pointer" }}>+ Add Your First Project</button>
            </div>
          ) : activeProjects.map(p => (
            <div key={p.id} onClick={() => goProject(p.id, "overview")}
              style={{ display:"flex", alignItems:"center", gap:14, padding:"12px 14px", background:C.cream, borderRadius:12, cursor:"pointer", border:`1px solid ${C.border}` }}>
              <div style={{ width:44, height:44, borderRadius:10, background:p.cover||C.ink, display:"flex", alignItems:"center", justifyContent:"center" }}>
                <Ic d={P[p.icon||"folder"]} size={20} style={{color:"rgba(255,255,255,0.85)", display:"block"}}/>
              </div>
              <div style={{ flex:1 }}>
                <p style={{ fontWeight:500, fontSize:14, color:C.ink }}>{p.name}</p>
                <p style={{ fontSize:12, color:C.muted, marginTop:2 }}>{p.client} · Due {p.due}</p>
              </div>
              <Badge s={p.status}/>
            </div>
          ))}
        </div>
      </Card>

      {/* Alerts */}
      <Card style={{ padding:22 }}>
        <h2 style={{ fontSize:15, fontWeight:600, color:C.ink, marginBottom:18 }}>Needs Attention</h2>
        <AlertList setPage={setPage}/>
        {ALERTS.length === 0 && (
          <div style={{ padding:"24px 0", textAlign:"center" }}>
            <p style={{ fontSize:13, color:C.muted }}>All caught up! Nothing needs attention right now.</p>
          </div>
        )}
      </Card>
    </div>

    {/* Recent gallery previews */}
    <Card style={{ padding:22 }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:18 }}>
        <h2 style={{ fontSize:15, fontWeight:600, color:C.ink }}>Recent Galleries</h2>
        <button onClick={() => setPage("projects")} style={{ fontSize:12, color:C.muted, background:"none", border:"none", cursor:"pointer" }}>View all →</button>
      </div>
      {projects.length === 0 ? (
        <div style={{ padding:"32px 0", textAlign:"center" }}>
          <p style={{ fontSize:13, color:C.muted }}>Galleries will appear here once you add projects.</p>
        </div>
      ) : (
        <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:12 }}>
          {projects.map(p => (
            <div key={p.id} onClick={() => goProject(p.id, "gallery")} style={{ cursor:"pointer", borderRadius:12, overflow:"hidden", border:`1px solid ${C.border}` }}
              onMouseEnter={e=>e.currentTarget.style.boxShadow="0 4px 16px rgba(0,0,0,.12)"} onMouseLeave={e=>e.currentTarget.style.boxShadow="none"}>
              <div style={{ background:p.cover||C.ink, height:120, display:"flex", alignItems:"center", justifyContent:"center" }}><Ic d={P[p.icon||"image"]} size={28} style={{color:"rgba(255,255,255,0.85)", display:"block"}}/></div>
              <div style={{ padding:"10px 12px" }}>
                <p style={{ fontSize:13, fontWeight:500, color:C.ink }}>{p.name}</p>
                <p style={{ fontSize:11, color:C.muted, marginTop:2 }}>{p.deliverables > 0 ? `${p.deliverables} photos` : "Shoot pending"}</p>
              </div>
            </div>
          ))}
        </div>
      )}
    </Card>
  </div>
  );
};

